class Solution(object):
    def maxPathLength(self, coordinates, k):
        """
        :type coordinates: List[List[int]]
        :type k: int
        :rtype: int
        """
        kx, ky = coordinates[k]

        # Get points before k: x < kx and y < ky
        before = []
        for i, (x, y) in enumerate(coordinates):
            if i != k and x < kx and y < ky:
                before.append((x, y))

        # Get points after k: x > kx and y > ky
        after = []
        for i, (x, y) in enumerate(coordinates):
            if i != k and x > kx and y > ky:
                after.append((x, y))

        def lis_length(points):
            """Calculate longest increasing subsequence by y-coordinate"""
            if not points:
                return 0
            # Sort by x, then by y descending (if x equal)
            points.sort(key=lambda p: (p[0], -p[1]))
            # Use LIS on y-coordinates
            from bisect import bisect_left
            tails = []
            for x, y in points:
                pos = bisect_left(tails, y)
                if pos == len(tails):
                    tails.append(y)
                else:
                    tails[pos] = y
            return len(tails)

        # Length = 1 (for k itself) + LIS before + LIS after
        return 1 + lis_length(before) + lis_length(after)
